from typing import Callable, TypeVar

T = TypeVar("T")
Predicate = Callable[[T], bool]

def first_match(items: list[T], pred: Predicate[T]) -> T | None:
    """Return the first item for which pred returns True, or None."""
    for item in items:
        if pred(item):
            return item
    return None

# Usage
tools = [{"name": "search"}, {"name": "code"}, {"name": "embed"}]
found = first_match(tools, lambda t: t["name"] == "code")
print(found)  # {'name': 'code'}

import functools, time
from typing import Callable, TypeVar, Type

F = TypeVar("F", bound=Callable)

def retry_on(
    *exc_types: Type[Exception],
    attempts: int = 3,
    backoff: float = 1.0,
) -> Callable[[F], F]:
    """Retry fn on any of the given exception types with exponential backoff."""
    def decorator(fn: F) -> F:
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            for attempt in range(attempts):
                try:
                    return fn(*args, **kwargs)
                except exc_types as exc:
                    if attempt == attempts - 1:
                        raise
                    wait = backoff * (2 ** attempt)
                    time.sleep(wait)
        return wrapper  # type: ignore[return-value]
    return decorator

