from typing import Callable

def compose(*wrappers: Callable[[Callable], Callable]) -> Callable[[Callable], Callable]:
    """Apply wrappers right-to-left so the leftmost runs outermost (first)."""
    def apply(fn: Callable) -> Callable:
        for wrapper in reversed(wrappers):
            fn = wrapper(fn)
        return fn
    return apply

# Define individual concerns
def with_logging(fn):
    @functools.wraps(fn)
    def inner(*a, **kw):
        print(f"→ {fn.__name__}")
        result = fn(*a, **kw)
        print(f"← {fn.__name__}")
        return result
    return inner

def with_timing(fn):
    @functools.wraps(fn)
    def inner(*a, **kw):
        t = time.perf_counter()
        r = fn(*a, **kw)
        print(f"{fn.__name__} took {(time.perf_counter()-t)*1000:.1f}ms")
        return r
    return inner

def run_tool(name: str, args: dict):
    return f"result_of_{name}"

# Stack: logging runs first (outer), timing second, then the raw function
execute = compose(with_logging, with_timing)(run_tool)
execute("search", {"q": "agents"})

