from typing import Callable, Any, TypeVar
import functools

T = TypeVar("T")
U = TypeVar("U")

class Step:
    """Wraps a callable as a composable pipeline step."""
    def __init__(self, fn: Callable[[Any], Any], name: str | None = None):
        self._fn = fn
        self.__name__ = name or getattr(fn, "__name__", repr(fn))

    def invoke(self, input_: Any) -> Any:
        return self._fn(input_)

    def __or__(self, other: "Step") -> "Pipeline":
        return Pipeline([self, other])

    @staticmethod
    def from_lambda(fn: Callable, name: str | None = None) -> "Step":
        return Step(fn, name=name)

class Pipeline:
    def __init__(self, steps: list[Step]):
        self._steps = steps

    def __or__(self, other: Step) -> "Pipeline":
        return Pipeline(self._steps + [other])

    def invoke(self, input_: Any) -> Any:
        result = input_
        for step in self._steps:
            result = step.invoke(result)
        return result

# Build a retrieval → rank → format pipeline from HOF-wrapped functions
retrieve   = Step.from_lambda(lambda q: [{"text": f"doc about {q}", "score": 0.9}], "retrieve")
rank       = Step.from_lambda(lambda chunks: sorted(chunks, key=lambda c: -c["score"]), "rank")
format_ctx = Step.from_lambda(lambda chunks: "\n".join(c["text"] for c in chunks), "format")

pipeline = retrieve | rank | format_ctx
print(pipeline.invoke("higher-order functions"))
