def bad_decorator(fn):
    def wrapper(*args, **kwargs):
        return fn(*args, **kwargs)
    return wrapper

@bad_decorator
def my_tool(q: str) -> str:
    """Search the knowledge base."""
    return q

print(my_tool.__name__)  # 'wrapper'   ← broken
print(my_tool.__doc__)   # None        ← lost

# RIGHT: @functools.wraps preserves metadata
import functools
def good_decorator(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        return fn(*args, **kwargs)
    return wrapper

@good_decorator
def my_tool(q: str) -> str:
    """Search the knowledge base."""
    return q

print(my_tool.__name__)  # 'my_tool'
print(my_tool.__doc__)   # 'Search the knowledge base.'

