from typing import Callable, ParamSpec, TypeVar

P = ParamSpec("P")   # captures parameter spec of wrapped function
R = TypeVar("R")     # return type

def logged(fn: Callable[P, R]) -> Callable[P, R]:
    @functools.wraps(fn)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        print(f"calling {fn.__name__}")
        return fn(*args, **kwargs)
    return wrapper

# Now mypy knows the wrapped function preserves its full signature
@logged
def call_llm(prompt: str, max_tokens: int = 512) -> str:
    return "response"

# Mypy correctly infers: call_llm(prompt="hi", max_tokens=256) -> str

def safe_wrapper(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        try:
            return fn(*args, **kwargs)
        except ValueError as exc:
            # Re-raise with context preserved — never silently swallow
            raise RuntimeError(f"{fn.__name__} received invalid input") from exc
    return wrapper
